// 1) Issue a Direct Creator Upload URL for Cloudflare Images
if (req.method === "POST" && url.pathname === "/images/direct-upload") {
  const endpoint = `https://api.cloudflare.com/client/v4/accounts/${env.CF_ACCOUNT_ID}/images/v2/direct_upload`;
  const r = await fetch(endpoint, {
    method: "POST",
    headers: { Authorization: `Bearer ${env.IMAGES_API_TOKEN}` },
    body: new FormData(), // optionally append metadata / requireSignedURLs here
  });
  const data = await r.json();
  return json(env, origin, data, r.ok ? 200 : 400);
}

/**
 * Canvas Viewport Controller
 * Centralizes all viewport transform math and eliminates coordinate drift.
 */

import { useCallback, useEffect, useRef, useState } from 'react';

export interface ViewportTransform {
  scale: number;
  tx: number; // translate X in world units
  ty: number; // translate Y in world units
}

export interface LockState {
  kind: 'locked';
  frameCenter: { x: number; y: number }; // world coordinates
}

export interface UnlockState {
  kind: 'unlocked';
}

export type ViewportLockState = LockState | UnlockState;

export interface ViewportBounds {
  width: number;
  height: number;
  x: number;
  y: number;
}

export interface UseCanvasViewportProps {
  containerRef: React.RefObject<HTMLElement>;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  frameBounds?: ViewportBounds;
  padding?: number;
}

export interface UseCanvasViewportReturn {
  transform: ViewportTransform;
  dpr: number;
  lockState: ViewportLockState;

  // Transform methods
  clientToWorld: (clientX: number, clientY: number) => { x: number; y: number };
  worldToClient: (worldX: number, worldY: number) => { x: number; y: number };

  // Lock methods
  setLock: (state: ViewportLockState) => void;
  zoomToFrame: (bounds: ViewportBounds) => void;

  // Layout scheduling
  scheduleLayout: () => void;
}

