fix.code:
async function directUploadHandler(req, res) {
    try {
        const origin = process.env.REMBG_ORIGIN || 'https://sofapaint-api.leigh-atkins.workers.dev';
        if (!origin) {
            return res.status(500).json({ success: false, message: 'REMBG_ORIGIN is not configured' });
        }

        console.log('[Proxy] Forwarding to:', `${origin}/images/direct-upload`);
        console.log('[Proxy] Client sent body:', req.body);

        const response = await fetch(`${origin.replace(/\/$/, '')}/images/direct-upload`, {
            method: 'POST',
            headers: {
                'x-api-key': req.headers['x-api-key'] || 'dev-secret'
            }
        });

        const data = await response.json();
        console.log('[Proxy] Worker response:', response.status, data);

        res.status(response.status).json(data);
    } catch (err) {
        console.error('[Proxy] /images/direct-upload error:', err);
        res.status(500).json({ success: false, message: 'Proxy error', error: err.message });
    }
}
